-- ============================================================
-- SAMPLE INVENTORY LEVELS (random stock across DCs)
-- ============================================================
insert into public.inventory_levels (organization_id, part_id, facility_id, quantity_on_hand, quantity_reserved, reorder_point, reorder_quantity)
select
  'a0000000-0000-0000-0000-000000000001',
  p.id,
  f.id,
  floor(random() * 50 + 2)::int,
  floor(random() * 5)::int,
  case when random() > 0.5 then 5 else 10 end,
  case when random() > 0.5 then 20 else 30 end
from public.parts p
cross join public.facilities f
where p.organization_id = 'a0000000-0000-0000-0000-000000000001'
  and f.organization_id = 'a0000000-0000-0000-0000-000000000001'
  and f.facility_type = 'distribution_center'
  and random() > 0.4
on conflict (part_id, facility_id) do nothing;
